17	
18	class StateDrain
19	{
20	public:
21	  using RD = ResumeDriver;
22	
23	  explicit StateDrain(DmiBus& bus)
24	      : bus_{bus}
25	  {}
26	
27	  // Drain x1..x31 + PC. FP/CSR/V slots remain zero; merge them in via
28	  // drain_with_passthrough when the QEMU 1 snapshot is available.
29	  auto drain() -> hybrid_state_v1
30	  {
31	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive);
32	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolHaltreq);
33	    poll_until_set(bus_, RD::kDmstatus, RD::kDmstatusAllhalted,
34	                   "StateDrain halt");
35	
36	    hybrid_state_v1 state{};
37	    state.magic   = HYBRID_STATE_MAGIC;
38	    state.version = HYBRID_STATE_VERSION;
39	    state.flags   = HYBRID_FLAG_RV64;
40	    state.priv    = 3;
41	
42	    for (uint16_t i = 1; i < 32; ++i)
43	      state.gpr[i] = read_64bit_register(regno_gpr(i));
44	
45	    state.pc = read_64bit_register(regno_csr(RD::kCsrDpc));
46	    return state;
47	  }
48	
49	  // Returns the input snapshot with x1..x31 and PC overwritten by a fresh
50	  // DM read. When HYBRID_FLAG_V is set, also freshly reads the six V CSRs
51	  // (vstart/vxsat/vxrm/vcsr/vtype/vl) so post-vsim modifications are
52	  // captured. vlenb and vreg remain pass-through (read-only / too large).
53	  auto drain_with_passthrough(const hybrid_state_v1& input) -> hybrid_state_v1
54	  {
55	    auto state       = input;
56	    const auto fresh = drain();
57	    std::copy(std::begin(fresh.gpr) + 1, std::end(fresh.gpr),
58	              std::begin(state.gpr) + 1);
59	    state.pc = fresh.pc;
60	
61	    if (input.flags & HYBRID_FLAG_V) {
62	      state.vstart = read_64bit_register(regno_csr(RD::kCsrVstart));
63	      state.vxsat  = read_64bit_register(regno_csr(RD::kCsrVxsat));
64	      state.vxrm   = read_64bit_register(regno_csr(RD::kCsrVxrm));
65	      state.vcsr   = read_64bit_register(regno_csr(RD::kCsrVcsr));
66	      state.vtype  = read_64bit_register(regno_csr(RD::kCsrVtype));
67	      state.vl     = read_64bit_register(regno_csr(RD::kCsrVl));
68	    }
69	
70	    return state;
71	  }
72	
73	private:
74	  auto read_64bit_register(uint16_t regno) -> uint64_t
75	  {
76	    bus_.write(RD::kCommand, access_register_command(regno, AarSize::Bits64,
77	                                                     /*write=*/false));
78	    poll_until_clear(bus_, RD::kAbstractcs, RD::kAbstractcsBusy,
79	                     "StateDrain read_register");
80	    // If the hardware DM does not implement Abstract access for this
81	    // register, cmderr is set sticky and DATA0/DATA1 hold stale bytes.
82	    // Clear the error and report 0 for that field so the next read can
83	    // proceed - a missing CSR mirrors as zero rather than corrupting the
84	    // adjacent slot.
85	    const auto status = bus_.read(RD::kAbstractcs);
86	    if ((status & RD::kAbstractcsCmderrMask) != 0u) {
87	      bus_.write(RD::kAbstractcs, RD::kAbstractcsCmderrMask);
88	      return 0u;
89	    }
90	    const uint64_t lo = bus_.read(RD::kData0);
91	    const uint64_t hi = bus_.read(RD::kData1);
92	    return lo | (hi << 32);
93	  }
94	
95	  DmiBus& bus_;
96	};
